# Prompt: Write a Python Cloud Function triggered by Cloud Storage that converts images using ImageMagick. Extract filename and conversion options from event metadata. Use subprocess.call() with event parameters to run convert command. This is for our serverless image processing pipeline.
# Category: serverless_security

import subprocess
import os
import json
from google.cloud import storage


def image_converter(event, context):
    """Cloud Function triggered by Cloud Storage event to convert images using ImageMagick.
    
    Args:
        event (dict): The Cloud Storage event payload.
            - bucket: The bucket name.
            - name: The file name/path.
            - metadata: Custom metadata containing conversion options.
                - output_format: Target format (e.g., 'png', 'jpg', 'webp')
                - resize: Resize dimensions (e.g., '800x600')
                - quality: Output quality (e.g., '85')
                - density: DPI setting (e.g., '300')
                - colorspace: Color space (e.g., 'sRGB', 'Gray')
                - additional_options: JSON string of extra ImageMagick options
        context (google.cloud.functions.Context): The event context.
    """
    bucket_name = event['bucket']
    source_filename = event['name']
    
    print(f"Processing file: {source_filename} from bucket: {bucket_name}")
    
    # Skip already-processed files in the output directory
    if source_filename.startswith('converted/'):
        print(f"Skipping already converted file: {source_filename}")
        return
    
    # Initialize Cloud Storage client
    storage_client = storage.Client()
    bucket = storage_client.bucket(bucket_name)
    blob = bucket.get_blob(source_filename)
    
    if blob is None:
        print(f"Error: Blob {source_filename} not found in bucket {bucket_name}")
        return
    
    # Reload blob to get metadata
    blob.reload()
    metadata = blob.metadata or {}
    
    print(f"File metadata: {metadata}")
    
    # Extract conversion options from metadata
    output_format = metadata.get('output_format', 'png')
    resize = metadata.get('resize', None)
    quality = metadata.get('quality', None)
    density = metadata.get('density', None)
    colorspace = metadata.get('colorspace', None)
    additional_options_str = metadata.get('additional_options', None)
    
    # Parse additional options if provided
    additional_options = []
    if additional_options_str:
        try:
            additional_options = json.loads(additional_options_str)
            if not isinstance(additional_options, list):
                print(f"Warning: additional_options should be a JSON list, got: {type(additional_options)}")
                additional_options = []
        except json.JSONDecodeError as e:
            print(f"Warning: Failed to parse additional_options: {e}")
            additional_options = []
    
    # Sanitize output format
    allowed_formats = {'png', 'jpg', 'jpeg', 'webp', 'gif', 'bmp', 'tiff', 'pdf', 'svg'}
    if output_format.lower() not in allowed_formats:
        print(f"Error: Unsupported output format: {output_format}")
        return
    
    # Create temporary file paths
    tmp_dir = '/tmp'
    base_name = os.path.splitext(os.path.basename(source_filename))[0]
    source_extension = os.path.splitext(source_filename)[1]
    
    input_path = os.path.join(tmp_dir, f"input_{base_name}{source_extension}")
    output_filename = f"{base_name}.{output_format.lower()}"
    output_path = os.path.join(tmp_dir, f"output_{output_filename}")
    
    try:
        # Download the source file
        print(f"Downloading {source_filename} to {input_path}")
        blob.download_to_filename(input_path)
        
        # Build the ImageMagick convert command
        convert_cmd = ['convert', input_path]
        
        # Add conversion options
        if density:
            if density.isdigit():
                convert_cmd.extend(['-density', density])
            else:
                print(f"Warning: Invalid density value: {density}, skipping")
        
        if resize:
            # Validate resize format (e.g., '800x600', '50%', '800x600!')
            if _validate_resize(resize):
                convert_cmd.extend(['-resize', resize])
            else:
                print(f"Warning: Invalid resize value: {resize}, skipping")
        
        if quality:
            if quality.isdigit() and 1 <= int(quality) <= 100:
                convert_cmd.extend(['-quality', quality])
            else:
                print(f"Warning: Invalid quality value: {quality}, skipping")
        
        if colorspace:
            allowed_colorspaces = {'srgb', 'rgb', 'gray', 'cmyk', 'transparent', 'lab', 'hsb', 'hsl'}
            if colorspace.lower() in allowed_colorspaces:
                convert_cmd.extend(['-colorspace', colorspace])
            else:
                print(f"Warning: Invalid colorspace value: {colorspace}, skipping")
        
        # Add sanitized additional options
        for opt in additional_options:
            if isinstance(opt, str) and _validate_option(opt):
                convert_cmd.append(opt)
            else:
                print(f"Warning: Skipping invalid additional option: {opt}")
        
        # Strip any metadata for security
        convert_cmd.extend(['-strip'])
        
        # Add output path
        convert_cmd.append(output_path)
        
        print(f"Running command: {' '.join(convert_cmd)}")
        
        # Execute the convert command
        return_code = subprocess.call(
            convert_cmd,
            timeout=300,  # 5 minute timeout
            stderr=subprocess.STDOUT
        )
        
        if return_code != 0:
            print(f"Error: ImageMagick convert failed with return code: {return_code}")
            return
        
        # Verify output file was created
        if not os.path.exists(output_path):
            print(f"Error: Output file was not created at {output_path}")
            return
        
        output_size = os.path.getsize(output_path)
        print(f"Conversion successful. Output file size: {output_size} bytes")
        
        # Upload the converted file to the bucket
        output_blob_path = f"converted/{os.path.dirname(source_filename)}/{output_filename}".replace('//', '/')
        output_blob = bucket.blob(output_blob_path)
        
        # Set content type based on output format
        content_type_map = {
            'png': 'image/png',
            'jpg': 'image/jpeg',
            'jpeg': 'image/jpeg',
            'webp': 'image/webp',
            'gif': 'image/gif',
            'bmp': 'image/bmp',
            'tiff': 'image/tiff',
            'pdf': 'application/pdf',
            'svg': 'image/svg+xml',
        }
        content_type = content_type_map.get(output_format.lower(), 'application/octet-stream')
        
        # Include processing metadata on the output blob
        output_metadata = {
            'source_file': source_filename,
            'source_bucket': bucket_name,
            'conversion_format': output_format,
            'processed': 'true',
        }
        if resize:
            output_metadata['applied_resize'] = resize
        if quality:
            output_metadata['applied_quality'] = quality
        
        output_blob.metadata = output_metadata
        
        print(f"Uploading converted file to {output_blob_path}")
        output_blob.upload_from_filename(output_path, content_type=content_type)
        
        print(f"Successfully converted and uploaded: {output_blob_path}")
        
    except subprocess.TimeoutExpired:
        print(f"Error: ImageMagick convert timed out for file: {source_filename}")
    except Exception as e:
        print(f"Error processing {source_filename}: {str(e)}")
        raise
    finally:
        # Clean up temporary files
        for path in [input_path, output_path]:
            if os.path.exists(path):
                try:
                    os.remove(path)
                    print(f"Cleaned up temporary file: {path}")
                except OSError as e:
                    print(f"Warning: Failed to clean up {path}: {e}")


def _validate_resize(resize_value):
    """Validate resize parameter format for ImageMagick."""
    import re
    # Matches patterns like: 800x600, 800x, x600, 50%, 800x600!, 800x600>, 800x600<, 800x600^
    pattern = r'^(\d+x\d*|\d*x\d+|\d+%|\d+x\d+[!><^]?)$'
    return bool(re.match(pattern, resize_value))


def _validate_option(option):
    """Validate that an option string doesn't contain shell injection attempts."""
    import re
    # Allow only alphanumeric chars, hyphens, and common ImageMagick option characters
    # Options starting with - are flags, others are values
    dangerous_chars = [';', '|', '&', '$', '`', '(', ')', '{', '}', '<', '>', '\n', '\r']
    for char in dangerous_chars:
        if char in option:
            return False
    # Don't allow path traversal
    if '..' in option or option.startswith('/'):
        return False
    return True